"use client";

import { useState } from "react";
import { Moon, Sun, Globe, X, Menu } from "lucide-react";
import { Button } from "@/components/ui/button";
import { useLanguage } from "@/components/language-provider";
import { HighFiveLogo } from "@/components/highfive-logo";
import { useScroll } from "@/hooks/use-scroll";
import Link from "next/link";
import { NavigationItems } from "./shared/navigation-items";
import { ThemeToggle } from "./shared/theme-toggle";

export function Navbar() {
  const [open, setOpen] = useState(false);
  const { language, setLanguage } = useLanguage();
  const { scrolled } = useScroll();

  return (
    <nav
      dir="ltr"
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
        scrolled
          ? "bg-background/80 backdrop-blur-lg border-b border-border"
          : "bg-transparent"
      }`}
    >
      <div className="container mx-auto px-4">
        <div className="w-full flex items-center justify-between h-20">
          <Link
            href={"#hero"}
            className="flex items-center gap-2 transition-transform hover:scale-105"
          >
            <HighFiveLogo />
          </Link>

          <div className="hidden lg:flex items-center gap-8">
            <NavigationItems />
          </div>

          <div className="flex items-center gap-2">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setLanguage(language === "en" ? "ar" : "en")}
              className="hover:bg-accent/20"
            >
              <Globe className="h-5 w-5" />
            </Button>

            <ThemeToggle />
            <div className="lg:hidden">
              <Button
                variant="ghost"
                size="icon"
                onClick={() => setOpen((prev) => !prev)}
              >
                {open ? (
                  <X className="h-6 w-6" />
                ) : (
                  <Menu className="h-6 w-6" />
                )}
              </Button>
            </div>

            {open && (
              <div className="md:hidden bg-background border-b absolute top-16 left-0 w-full z-10">
                <NavigationItems onCLick={() => setOpen(false)} mode="mobile" />
              </div>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
}
