"use client";

import { Button } from "@/components/ui/button";
import { ArrowLeft, ArrowRight, Sparkles } from "lucide-react";
import { useLanguage } from "@/components/language-provider";
import { ThreeJsScene } from "@/components/threejs-scene";
import { cn } from "@/lib/utils";
import { useTheme } from "./theme-provider";

export function HeroSection() {
  const { t, language } = useLanguage();
  const { theme } = useTheme();

  const scrollToSection = (id: string) => {
    const element = document.getElementById(id);
    if (element) {
      const offset = 80;
      const elementPosition = element.getBoundingClientRect().top;
      const offsetPosition = elementPosition + window.pageYOffset - offset;

      window.scrollTo({
        top: offsetPosition,
        behavior: "smooth",
      });
    }
  };

  return (
    <section
      id="hero"
      className="relative min-h-screen flex items-center justify-center overflow-hidden pt-20"
    >
      <div className="absolute inset-0 z-0">
        <ThreeJsScene />
      </div>

      <div className="container mx-auto px-4 z-10 relative">
        <div className="max-w-4xl mx-auto text-center">
          <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-primary/10 border border-primary/20 mb-8 animate-fade-in">
            <Sparkles className="w-4 h-4 text-primary" />
            <span className="text-sm font-medium text-primary">
              {language === "ar"
                ? "مدعوم بالذكاء الاصطناعي"
                : "AI-Powered Solutions"}
            </span>
          </div>

          <h1
            className={cn(
              "text-5xl md:text-7xl text-muted-foreground font-bold mb-6 text-balance animate-in"
            )}
          >
            {t("hero.title")}
            <br />
            <span className="bg-linear-to-r from-primary via-accent to-secondary bg-clip-text text-transparent">
              {t("hero.subtitle")}
            </span>
          </h1>

          <p
            className={cn(
              "text-lg md:text-xl text-muted-foreground mb-10 max-w-2xl mx-auto text-pretty center animate-fade-in-up animation-delay-200"
            )}
          >
            {t("hero.description")}
          </p>

          <div className="flex flex-col sm:flex-row items-center justify-center gap-4 animate-fade-in-up animation-delay-400">
            <Button
              size="lg"
              onClick={() => scrollToSection("contact")}
              className="bg-primary hover:bg-primary/90 text-primary-foreground group"
            >
              {t("hero.cta.primary")}
              {language === "en" ? (
                <ArrowRight className="ml-2 h-5 w-5 transition-transform group-hover:translate-x-1" />
              ) : (
                <ArrowLeft className="ml-2 h-5 w-5 transition-transform group-hover:translate-x-1" />
              )}
            </Button>
            <Button
              size="lg"
              variant="outline"
              onClick={() => scrollToSection("services")}
              className="border-primary/20 hover:bg-primary/10"
            >
              {t("hero.cta.secondary")}
            </Button>
          </div>
        </div>
      </div>
    </section>
  );
}
